import { useState } from "react";
import axios from "axios";
import {
  Upload,
  Button,
  Steps,
  Alert,
  Typography,
  Space,
  Card,
  Progress,
  theme,
} from "antd";
import {
  InboxOutlined,
  DownloadOutlined,
  LoadingOutlined,
  CheckCircleOutlined,
} from "@ant-design/icons";
import type { UploadFile, UploadProps } from "antd";

const { Dragger } = Upload;
const { Title, Text, Paragraph } = Typography;


// ─── TODO: вставь адрес своего бека ──────────────────────────────────────────
const PROCESS_ENDPOINT = "/process-video";
// ─────────────────────────────────────────────────────────────────────────────

type AppStep = "idle" | "uploading" | "processing" | "done" | "error";

export default function App() {
  const { token } = theme.useToken();

  const [step, setStep] = useState<AppStep>("idle");
  const [fileList, setFileList] = useState<UploadFile[]>([]);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [csvBlob, setCsvBlob] = useState<Blob | null>(null);
  const [errorMessage, setErrorMessage] = useState<string>("");

  // ─── Единственный запрос: POST /process-video ──────────────────────────────
  // Бек принимает multipart/form-data с полем "file", синхронно запускает
  // video_detect.py и возвращает готовый CSV-файл (FileResponse).
  const handleUpload = async () => {
    const file = fileList[0]?.originFileObj;
    if (!file) return;

    setStep("uploading");
    setUploadProgress(0);
    setCsvBlob(null);

    const formData = new FormData();
    formData.append("file", file); // имя поля совпадает с параметром FastAPI: file: UploadFile

    try {
      const response = await axios.post(PROCESS_ENDPOINT, formData, {
        headers: { "Content-Type": "multipart/form-data" },
        responseType: "blob", // ждём бинарный CSV в ответе
        onUploadProgress: (e) => {
          // прогресс только для фазы загрузки файла на сервер;
          // пока бек обрабатывает видео — будет висеть на 100% до ответа
          const percent = Math.round((e.loaded * 100) / (e.total ?? 1));
          setUploadProgress(percent);
          if (percent === 100) setStep("processing");
        },
      });

      const blob = new Blob([response.data], { type: "text/csv;charset=utf-8;" });
      setCsvBlob(blob);
      triggerDownload(blob);
      setStep("done");
    } catch (err) {
      setStep("error");

      // Если бек вернул { status: "error", message: "..." } — парсим из blob
      if (axios.isAxiosError(err) && err.response?.data instanceof Blob) {
        const text = await err.response.data.text();
        try {
          const json = JSON.parse(text);
          setErrorMessage(json.message ?? text);
        } catch {
          setErrorMessage(text);
        }
      } else {
        setErrorMessage(
            axios.isAxiosError(err) ? err.message : "Неизвестная ошибка"
        );
      }
    }
  };

  // ─── Хелпер: программный клик по скрытой ссылке ────────────────────────────
  const triggerDownload = (blob: Blob, filename = "result.csv") => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  };

  // ─── Повторить скачивание без нового запроса ───────────────────────────────
  const handleDownloadAgain = () => {
    if (csvBlob) triggerDownload(csvBlob);
  };

  // ─── Сброс формы ───────────────────────────────────────────────────────────
  const handleReset = () => {
    setStep("idle");
    setFileList([]);
    setUploadProgress(0);
    setCsvBlob(null);
    setErrorMessage("");
  };

  // ─── Конфиг Dragger (только выбор, без авто-загрузки) ──────────────────────
  const uploadProps: UploadProps = {
    accept: "video/*",
    multiple: false,
    beforeUpload: () => false, // отключаем авто-загрузку Ant Design
    fileList,
    onChange: ({ fileList: newList }) => setFileList(newList.slice(-1)), // максимум 1 файл
  };

  // ─── Вычисляем текущий шаг для <Steps> ─────────────────────────────────────
  const currentStepIndex: Record<AppStep, number> = {
    idle: 0,
    uploading: 0,
    processing: 1,
    done: 2,
    error: 2,
  };

  return (
      <div
          style={{
            minHeight: "100vh",
            background: token.colorBgLayout,
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            padding: "40px 16px",
          }}
      >
        <Card
            style={{ width: "100%", maxWidth: 640 }}
            styles={{ body: { padding: "40px 48px" } }}
        >
          {/* Заголовок */}
          <Space direction="vertical" size={4} style={{ marginBottom: 32 }}>
            <Title level={3} style={{ margin: 0 }}>
              Анализ видео
            </Title>
            <Paragraph type="secondary" style={{ margin: 0 }}>
              Загрузи видеофайл — получи результат в&nbsp;CSV
            </Paragraph>
          </Space>

          {/* Прогресс шагов */}
          <Steps
              size="small"
              current={currentStepIndex[step]}
              status={step === "error" ? "error" : undefined}
              style={{ marginBottom: 32 }}
              items={[
                { title: "Загрузка" },
                { title: "Обработка" },
                { title: "Готово" },
              ]}
          />

          {/* Зона загрузки */}
          {step === "idle" && (
              <Space direction="vertical" size={16} style={{ width: "100%" }}>
                <Dragger {...uploadProps} style={{ borderRadius: 8 }}>
                  <p className="ant-upload-drag-icon">
                    <InboxOutlined style={{ fontSize: 40, color: token.colorPrimary }} />
                  </p>
                  <p className="ant-upload-text">
                    Кликни или перетащи файл сюда
                  </p>
                  <p className="ant-upload-hint">
                    Поддерживаются все распространённые форматы видео (mp4, mov, avi…)
                  </p>
                </Dragger>

                <Button
                    type="primary"
                    size="large"
                    block
                    disabled={fileList.length === 0}
                    onClick={handleUpload}
                >
                  Отправить
                </Button>
              </Space>
          )}

          {/* Прогресс-бар загрузки */}
          {step === "uploading" && (
              <Space direction="vertical" size={16} style={{ width: "100%" }}>
                <Text>Загрузка файла…</Text>
                <Progress percent={uploadProgress} status="active" />
              </Space>
          )}

          {/* Индикатор обработки */}
          {step === "processing" && (
              <Space size={12} align="center">
                <LoadingOutlined style={{ fontSize: 24, color: token.colorPrimary }} />
                <Text>Сервер обрабатывает видео, подожди немного…</Text>
              </Space>
          )}

          {/* Успех */}
          {step === "done" && (
              <Space direction="vertical" size={16} style={{ width: "100%" }}>
                <Alert
                    type="success"
                    showIcon
                    icon={<CheckCircleOutlined />}
                    message="Готово! CSV-файл скачан автоматически."
                />
                <Space>
                  <Button icon={<DownloadOutlined />} onClick={handleDownloadAgain}>
                    Скачать ещё раз
                  </Button>
                  <Button onClick={handleReset}>Загрузить другое видео</Button>
                </Space>
              </Space>
          )}

          {/* Ошибка */}
          {step === "error" && (
              <Space direction="vertical" size={16} style={{ width: "100%" }}>
                <Alert
                    type="error"
                    showIcon
                    message="Что-то пошло не так"
                    description={errorMessage}
                />
                <Button onClick={handleReset}>Попробовать снова</Button>
              </Space>
          )}
        </Card>
      </div>
  );
}